import{_ as t,o as r,c as o,a2 as e}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"G07: 研發成果實質性 - 產品經理 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/8064_東捷/20260429/G07_研發成果實質性_產品經理.md","filePath":"審計報告庫/經營審計/8064_東捷/20260429/G07_研發成果實質性_產品經理.md"}'),i={name:"審計報告庫/經營審計/8064_東捷/20260429/G07_研發成果實質性_產品經理.md"};function l(n,a,s,c,h,d){return r(),o("div",null,[...a[0]||(a[0]=[e('<h1 id="g07-研發成果實質性-產品經理-審計報告" tabindex="-1">G07: 研發成果實質性 - 產品經理 審計報告 <a class="header-anchor" href="#g07-研發成果實質性-產品經理-審計報告" aria-label="Permalink to &quot;G07: 研發成果實質性 - 產品經理 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>最近三年研發成果預期項目是否有如期完成？最近三年重大研發成果為何？具備何種變現潛力？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：研發佔營收自4.8%升至7.5%，營收卻從39.2億縮至26.0億，投入與成長脫節。FOPLP、Micro LED量產未貢獻，專利淨額僅511萬。</li><li><strong>風險評級</strong>：高</li><li><strong>數據時效</strong>：截至114年</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>：研發費用111年1.87億→114年1.76億；營收111年39.2億→113年26.0億→114年28.7億；研發集約度111年4.8%→113年7.5%→114年6.1%；專利淨額114年511萬（三年增156萬），資本化0%。</li><li><strong>診斷見解</strong>：集約度上升係營收萎縮分母效應，114年營收回升但研發縮減，與轉型戰略矛盾。專利轉化率&lt;0.2%。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="一、研發項目完成度" tabindex="-1">一、研發項目完成度 <a class="header-anchor" href="#一、研發項目完成度" aria-label="Permalink to &quot;一、研發項目完成度&quot;">​</a></h3><p>FOPLP與Micro LED均處「技術驗證完成、量產部署啟動」階段。FOPLP雷射設備已於Touch Taiwan展示，但與客戶共同開發中，尚未獨立出貨。Micro LED巨量轉移已獲訂單，2024年出貨成長，然車載認證需2-3年。研發落地率推估&lt;30%，項目進入持續延展循環而非如期完成。</p><h3 id="二、變現潛力" tabindex="-1">二、變現潛力 <a class="header-anchor" href="#二、變現潛力" aria-label="Permalink to &quot;二、變現潛力&quot;">​</a></h3><p>FOPLP已進入群創供應鏈，但客戶集中度高，議價薄弱。Micro LED設備已取訂單，2025年為投資高峰，然產業仍處成本下降曲線。公司預期2026年半導體設備佔比超三成，但轉型高度依賴產業景氣。變現潛力存在但不確定性高，缺乏終端定價權。</p><h3 id="三、專利防禦力" tabindex="-1">三、專利防禦力 <a class="header-anchor" href="#三、專利防禦力" aria-label="Permalink to &quot;三、專利防禦力&quot;">​</a></h3><p>專利淨額114年底511萬，三年增38%，24項專利對照年研發逾1.7億，產出比極低。多數為改良型非基礎發明，技術防禦力判定為零散且易被跨越。</p><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一：研發黑洞效應</strong>。三年累計研發支出逾 7.7 億元，但專利資產淨額僅增 156 萬，營收從 39.2 億萎縮至 26.0 億（114年回升至 28.7 億但仍低於 111年水準）。研發投入的經濟回報率（ROIC）極低，若 FOPLP 與 Micro LED 量產時程再延遲一年，公司將面臨「研發費用侵蝕獲利」的結構性風險。</li><li><strong>空頭風險二：客戶集中與技術替代雙殺</strong>。FOPLP 設備高度依賴群創單一客戶，Micro LED 車載認證需 2-3 年。若面板產業資本支出持續收縮，或 OLED 技術在中小尺寸應用取得成本突破，東捷的兩大研發主軸可能同時面臨「市場蒸發」風險。公司 111-113 年營收連續三年下滑，已驗證下游需求的脆弱性。</li><li><strong>空頭風險三：研發費用資本化疑慮</strong>。公司研發支出全數費用化，表面財務透明，但若未來將研發支出轉為資本化處理以美化損益表，將是重要的財務紅旗訊號。投資人應持續追蹤「無形資產-開發成本」科目變化。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind</strong>: OK（營收、毛利、營業費用數據提取正常）</li><li><strong>年報/財報</strong>: OK（114/113年度合併財報、113/112年度合併財報、112/111年度合併財報均已讀取）</li><li><strong>研發費用</strong>: 111年 187,114千（財報第9頁）→ 112年 213,674千（財報第9頁）→ 113年 195,344千（財報第9頁）→ 114年 176,213千（財報第9頁）</li><li><strong>專利資產</strong>: 114年底淨額 5,111千（財報附註十八）、113年底淨額 4,326千（財報附註十八）</li><li><strong>營業收入（合併）</strong>: 111年 3,920,549千 → 112年 2,990,451千 → 113年 2,603,886千 → 114年 2,870,684千（各年度財報第9頁）</li><li><strong>法說會資訊</strong>: 2025年Q3法說會揭示FOPLP/Micro LED策略佈局（來源：poorstock.com、cmoney）</li><li><strong>專利數量</strong>: 公司宣稱持有24項專利（來源：公開資訊觀測站、法人說明會）</li><li><strong>關鍵核對碼</strong>: 研發費用YoY: +14.2%(111→112), -8.9%(112→113), -9.8%(113→114); 專利淨額三年增156萬</li></ul>',18)])])}const g=t(i,[["render",l]]);export{u as __pageData,g as default};
